// 语义分析节点
const query = items[0].json.query;
const userId = items[0].json.user_id || 'default';

// 调用意图分析API
const intentResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://ai-workflow-backend:8000/api/intent/analyze',
  body: { query },
  json: true
});

return [{
  json: {
    query,
    user_id: userId,
    intent: intentResponse.data,
    timestamp: new Date().toISOString()
  }
}];

// 任务规划节点
const { query, intent } = items[0].json;

// 调用任务规划API
const planResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://ai-workflow-backend:8000/api/task/plan',
  body: { query, intent },
  json: true
});

return [{
  json: {
    ...items[0].json,
    tasks: planResponse.data
  }
}];

// 知识检索节点
const { query } = items[0].json;

// 调用向量检索API
const searchResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://ai-workflow-backend:8000/api/knowledge/search',
  body: { query, top_k: 5 },
  json: true
});

return [{
  json: {
    ...items[0].json,
    knowledge: searchResponse.data
  }
}];

// 推理生成节点
const { query, intent, tasks, knowledge } = items[0].json;

// 调用推理模型API
const reasoningResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://ai-workflow-backend:8000/api/reasoning/generate',
  body: { query, intent, tasks, knowledge },
  json: true
});

return [{
  json: {
    ...items[0].json,
    reasoning: reasoningResponse.data,
    workflow_id: `wf_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
  }
}];

// 结果存储节点
const workflowData = items[0].json;

// 异步存储到向量数据库
const storeResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://ai-workflow-backend:8000/api/knowledge/store',
  body: {
    workflow_id: workflowData.workflow_id,
    content: workflowData.reasoning.output.content,
    metadata: {
      query: workflowData.query,
      intent: workflowData.intent.category,
      timestamp: workflowData.timestamp
    }
  },
  json: true
});

// 返回最终结果
return [{
  json: {
    success: true,
    workflow_id: workflowData.workflow_id,
    result: workflowData.reasoning.output,
    execution_summary: {
      intent: workflowData.intent,
      tasks_count: workflowData.tasks.length,
      knowledge_count: workflowData.knowledge.length,
      stored: storeResponse.success
    }
  }
}];
